import React, { useEffect, useState } from "react";
import axios from "axios";
import { Container, Table, Button, Form } from "react-bootstrap";
import { useAuth } from "../context/AuthContext";

function Appointments() {
  const { user } = useAuth();
  const [appointments, setAppointments] = useState([]);
  const [form, setForm] = useState({
    doctor_name: "",
    date_time: "",
    notes: "",
  });

  const fetchAppointments = async () => {
    const res = await axios.get(`/api/appointments/${user.id}`);
    setAppointments(res.data);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    await axios.post("/api/appointments", { ...form, user_id: user.id });
    setForm({ doctor_name: "", date_time: "", notes: "" });
    fetchAppointments();
  };

  useEffect(() => {
    if (user) fetchAppointments();
  }, [user]);

  return (
    <Container className="mt-4">
      <h3>Your Appointments</h3>
      <Form onSubmit={handleSubmit} className="my-3">
        <Form.Control
          placeholder="Doctor's Name"
          value={form.doctor_name}
          onChange={(e) => setForm({ ...form, doctor_name: e.target.value })}
        />
        <Form.Control
          className="mt-2"
          type="datetime-local"
          value={form.date_time}
          onChange={(e) => setForm({ ...form, date_time: e.target.value })}
        />
        <Form.Control
          className="mt-2"
          placeholder="Notes"
          value={form.notes}
          onChange={(e) => setForm({ ...form, notes: e.target.value })}
        />
        <Button type="submit" className="mt-2">Add Appointment</Button>
      </Form>

      <Table striped bordered hover>
        <thead>
          <tr>
            <th>Doctor</th>
            <th>Date</th>
            <th>Notes</th>
          </tr>
        </thead>
        <tbody>
          {appointments.map((a) => (
            <tr key={a.id}>
              <td>{a.doctor_name}</td>
              <td>{new Date(a.date_time).toLocaleString()}</td>
              <td>{a.notes}</td>
            </tr>
          ))}
        </tbody>
      </Table>
    </Container>
  );
}

export default Appointments;
